/**
 * PRD version 2.26.2 - sync with docs/FOS-Dashboard-PRD.md
 *
 * Bundled favicon PNG bytes (base64). Mirrored to Drive for HtmlOutput.setFaviconUrl
 * (Apps Script ignores <link rel="icon"> in HTML files and rejects data: URLs).
 * Regenerate: powershell -File scripts/embed-favicon.ps1
 */

/** @const {string} */
var FOS_FAVICON_PNG_BASE64_ = '';

/** @const {string} Script property: Drive file id for mirrored favicon PNG. */
var FOS_FAVICON_DRIVE_FILE_ID_PROP_ = 'FOS_FAVICON_DRIVE_FILE_ID';

/** @const {string} Script property: SHA-256 hex of bundled PNG for mirror invalidation. */
var FOS_FAVICON_CONTENT_HASH_PROP_ = 'FOS_FAVICON_CONTENT_HASH';

/**
 * @return {GoogleAppsScript.Base.Blob}
 */
function getFaviconPngBlob_() {
  return Utilities.newBlob(
    Utilities.base64Decode(FOS_FAVICON_PNG_BASE64_),
    'image/png',
    'favicon.png'
  );
}

/**
 * SHA-256 hex digest of bundled PNG bytes.
 *
 * @return {string}
 * @private
 */
function getFaviconContentHash_() {
  var digest = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    Utilities.base64Decode(FOS_FAVICON_PNG_BASE64_)
  );
  return digest
    .map(function (b) {
      var n = b < 0 ? b + 256 : b;
      var h = n.toString(16);
      return h.length === 1 ? '0' + h : h;
    })
    .join('');
}

/**
 * Drive download URL with &.png suffix (Apps Script setFaviconUrl needs HTTPS + extension).
 *
 * @param {string} fileId
 * @return {string}
 * @private
 */
function getFaviconDriveUrl_(fileId) {
  return 'https://drive.google.com/uc?id=' + encodeURIComponent(fileId) + '&.png';
}

/**
 * Creates or updates a public Drive mirror of the bundled PNG.
 *
 * @param {GoogleAppsScript.Base.Blob} blob
 * @param {string} hash
 * @param {GoogleAppsScript.Properties.Properties} props
 * @return {string} Drive file id
 * @private
 */
function ensureFaviconDriveMirror_(blob, hash, props) {
  var fileId = props.getProperty(FOS_FAVICON_DRIVE_FILE_ID_PROP_);
  if (fileId) {
    try {
      var oldFile = DriveApp.getFileById(fileId);
      var folder = null;
      var parents = oldFile.getParents();
      if (parents.hasNext()) {
        folder = parents.next();
      }
      oldFile.setTrashed(true);
      var replacement = folder ? folder.createFile(blob) : DriveApp.createFile(blob);
      replacement.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
      props.setProperty(FOS_FAVICON_DRIVE_FILE_ID_PROP_, replacement.getId());
      props.setProperty(FOS_FAVICON_CONTENT_HASH_PROP_, hash);
      return replacement.getId();
    } catch (e) {
      /* fall through - create fresh */
    }
  }

  var created = DriveApp.createFile(blob);
  created.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
  props.setProperty(FOS_FAVICON_DRIVE_FILE_ID_PROP_, created.getId());
  props.setProperty(FOS_FAVICON_CONTENT_HASH_PROP_, hash);
  return created.getId();
}

/**
 * HTTPS PNG URL for HtmlOutput.setFaviconUrl. Mirrors bundled bytes to Drive on first use
 * (and when embed hash changes). Returns empty string on failure so doGet still renders.
 *
 * @return {string}
 */
function getFaviconUrlForWebApp_() {
  try {
    var props = PropertiesService.getScriptProperties();
    var hash = getFaviconContentHash_();
    var storedHash = props.getProperty(FOS_FAVICON_CONTENT_HASH_PROP_);
    var fileId = props.getProperty(FOS_FAVICON_DRIVE_FILE_ID_PROP_);
    var blob = getFaviconPngBlob_();

    if (fileId && storedHash === hash) {
      try {
        DriveApp.getFileById(fileId);
        return getFaviconDriveUrl_(fileId);
      } catch (e) {
        fileId = null;
      }
    }

    fileId = ensureFaviconDriveMirror_(blob, hash, props);
    return getFaviconDriveUrl_(fileId);
  } catch (e) {
    try {
      console.warn(
        'getFaviconUrlForWebApp_: Drive mirror failed: ' + (e && e.message ? e.message : e)
      );
    } catch (_) {
      /* ignore */
    }
    return '';
  }
}
